const { Client } = require('pg');

const client = new Client({
  user: 'postgres',
  host: 'localhost',
  database: 'your_database',
  password: 'your_password',
  port: 5432,
});

client.connect();

// Create operation
const createRecord = async (tableName, data) => {
  try {
    const columns = Object.keys(data).join(', ');
    const values = Object.values(data);
    const placeholders = values.map((_, index) => `$${index + 1}`).join(', ');
    
    const query = `INSERT INTO ${tableName} (${columns}) VALUES (${placeholders}) RETURNING *`;
    const result = await client.query(query, values);
    return result.rows[0];
  } catch (error) {
    throw error;
  }
};

// Read operation
const getRecords = async (tableName, conditions = {}) => {
  try {
    let query = `SELECT * FROM ${tableName}`;
    const values = [];
    
    if (Object.keys(conditions).length > 0) {
      const whereClause = Object.keys(conditions)
        .map((key, index) => `${key} = $${index + 1}`)
        .join(' AND ');
      query += ` WHERE ${whereClause}`;
      values.push(...Object.values(conditions));
    }
    
    const result = await client.query(query, values);
    return result.rows;
  } catch (error) {
    throw error;
  }
};

// Update operation
const updateRecord = async (tableName, data, conditions) => {
  try {
    const setClause = Object.keys(data)
      .map((key, index) => `${key} = $${index + 1}`)
      .join(', ');
    const values = [...Object.values(data), ...Object.values(conditions)];
    
    const whereClause = Object.keys(conditions)
      .map((key, index) => `${key} = $${index + 1 + Object.values(data).length}`)
      .join(' AND ');
    
    const query = `UPDATE ${tableName} SET ${setClause} WHERE ${whereClause} RETURNING *`;
    const result = await client.query(query, values);
    return result.rows[0];
  } catch (error) {
    throw error;
  }
};

// Delete operation
const deleteRecord = async (tableName, conditions) => {
  try {
    const whereClause = Object.keys(conditions)
      .map((key, index) => `${key} = $${index + 1}`)
      .join(' AND ');
    const values = Object.values(conditions);
    
    const query = `DELETE FROM ${tableName} WHERE ${whereClause} RETURNING *`;
    const result = await client.query(query, values);
    return result.rows[0];
  } catch (error) {
    throw error;
  }
};

// Example usage for multiple tables
const exampleUsage = async () => {
  try {
    // Create users
    const newUser = await createRecord('users', {
      name: 'John Doe',
      email: 'john@example.com'
    });
    
    // Create posts
    const newPost = await createRecord('posts', {
      title: 'My First Post',
      content: 'Hello World',
      user_id: newUser.id
    });
    
    // Get all users
    const allUsers = await getRecords('users');
    
    // Get specific user
    const specificUser = await getRecords('users', { id: newUser.id });
    
    // Update user
    const updatedUser = await updateRecord('users', { name: 'Jane Doe' }, { id: newUser.id });
    
    // Delete user
    const deletedUser = await deleteRecord('users', { id: newUser.id });
    
    console.log('Example operations completed successfully');
  } catch (error) {
    console.error('Error in example operations:', error);
  }
};

// Run example
exampleUsage();

